(function () {
  function addStyle() { if (document.getElementById('rv-style')) return; var s = document.createElement('style'); s.id = 'rv-style'; s.textContent = '.rv-wrap{border:1px solid #e5e7eb;border-radius:12px;padding:16px;background:#fff;margin:14px 0}.rv-controls{display:grid;grid-template-columns:repeat(auto-fit,minmax(160px,1fr));gap:12px;align-items:end}.rv-controls label{display:flex;flex-direction:column;gap:5px}.rv-controls input,.rv-controls select{padding:8px;border:1px solid #cbd5e1;border-radius:8px}.rv-rule{margin:12px 0;padding:10px;border-left:4px solid #007bff;background:#e8f4fd;border-radius:8px}.rv-table{width:100%;border-collapse:collapse;margin-top:10px}.rv-table th,.rv-table td{border:1px solid #e5e7eb;padding:8px;text-align:center}.rv-table tr:last-child{background:#fff8dc}.rv-closed{margin-top:10px;padding:10px;background:#f8f9fa;border-radius:8px}'; document.head.appendChild(s); }
  function mount(host) { if (!host || host.dataset.rvMounted) return; host.dataset.rvMounted = '1'; addStyle(); host.innerHTML = '<div class="rv-wrap"><h4>🔁 Trực quan quan hệ truy hồi</h4><div class="rv-controls"><label>Loại truy hồi <select data-type><option value="fib">Fibonacci</option><option value="fac">Factorial</option><option value="custom">Custom: a_n = 2a_{n-1} + 3</option></select></label><label>n <input data-n type="number" min="0" max="15" value="8"></label><button type="button" data-calc>Tính</button></div><div class="rv-rule"></div><table class="rv-table"></table><div class="rv-closed"></div></div>'; var type = host.querySelector('[data-type]'), nEl = host.querySelector('[data-n]'), rule = host.querySelector('.rv-rule'), table = host.querySelector('.rv-table'), closed = host.querySelector('.rv-closed'); function calc() { var n = Math.max(0, Math.min(15, parseInt(nEl.value, 10) || 0)), seq = [], rel = '', cf = ''; nEl.value = n; if (type.value === 'fib') { rel = 'F_n = F_{n-1} + F_{n-2}, F_0 = 0, F_1 = 1'; cf = 'Công thức đóng: F_n = (φ^n - ψ^n)/√5.'; for (var i = 0; i <= n; i++) seq[i] = i < 2 ? i : seq[i - 1] + seq[i - 2]; } else if (type.value === 'fac') { rel = 'a_n = n × a_{n-1}, a_0 = 1'; cf = 'Công thức đóng: a_n = n!.'; for (i = 0; i <= n; i++) seq[i] = i === 0 ? 1 : i * seq[i - 1]; } else { rel = 'a_n = 2a_{n-1} + 3, a_0 = 1'; cf = 'Công thức đóng: a_n = 4×2^n - 3.'; for (i = 0; i <= n; i++) seq[i] = i === 0 ? 1 : 2 * seq[i - 1] + 3; } rule.innerHTML = '<strong>Quan hệ:</strong> ' + rel; table.innerHTML = '<tr><th>n</th>' + seq.map(function (_, i) { return '<th>' + i + '</th>'; }).join('') + '</tr><tr><th>a_n</th>' + seq.map(function (x) { return '<td>' + x + '</td>'; }).join('') + '</tr>'; closed.textContent = cf; } host.querySelector('[data-calc]').addEventListener('click', calc); type.addEventListener('change', calc); nEl.addEventListener('input', calc); calc(); }
  document.addEventListener('DOMContentLoaded', function () { document.querySelectorAll('[data-demo="recurrence-visualizer"]').forEach(mount); });
}());
